<div class="container-fluid">
	<div class="d-sm-flex align-items-center justify-content-between mb-4"><h1 class="h3 mb-0 text-gray-800">Edit Admin User</h1><a href="<?php echo site_url('admin/admin_user'); ?>" class="btn btn-sm btn-secondary"><i class="fas fa-arrow-left mr-1"></i> Kembali</a></div>
