			<div class="row"><div class="col-md-6"><div class="form-group"><label>Nama Lengkap</label><input type="text" class="form-control" name="nama" required value="<?php echo htmlspecialchars($item['nama'], ENT_QUOTES, 'UTF-8'); ?>"></div></div><div class="col-md-6"><div class="form-group"><label>Username</label><input type="text" class="form-control" name="username" required value="<?php echo htmlspecialchars($item['username'], ENT_QUOTES, 'UTF-8'); ?>" autocomplete="off"></div></div></div>
			<div class="row"><div class="col-md-8"><div class="form-group"><label>Password Baru</label><input type="password" class="form-control" name="password_hash" minlength="8" autocomplete="new-password"><small class="form-text text-muted">Kosongkan jika password tidak diganti.</small></div></div><div class="col-md-4"><div class="form-group"><label>Status</label><select class="form-control" name="status"><option value="aktif" <?php echo $item['status'] === 'aktif' ? 'selected' : ''; ?>>Aktif</option><option value="nonaktif" <?php echo $item['status'] === 'nonaktif' ? 'selected' : ''; ?>>Nonaktif</option></select></div></div></div>
