<script>
document.addEventListener('DOMContentLoaded',function(){$('.dropify').dropify({messages:{default:'Seret foto atau klik untuk memilih',replace:'Seret foto atau klik untuk mengganti',remove:'Hapus',error:'Terjadi kesalahan'}});$('#formEditAdmin').on('submit',function(event){event.preventDefault();var button=$('#simpanAdmin').prop('disabled',true);$('#pesanAdmin').addClass('d-none');$.ajax({url:'<?php echo site_url('admin/admin_user/edit'); ?>',type:'POST',data:new FormData(this),processData:false,contentType:false,dataType:'json',success:function(result){if(result.status)window.location.href='<?php echo site_url('admin/admin_user'); ?>';else $('#pesanAdmin').removeClass('d-none').text(result.message||'Data gagal diperbarui.');},error:function(){$('#pesanAdmin').removeClass('d-none').text('Terjadi kesalahan saat memperbarui data.');},complete:function(){button.prop('disabled',false);}});});});
</script>
